      prompt: `Which choice completes the text so that it conforms to the conventions of Standard English?`,
      options: [{ id: `A`, text: `phenomenon and in` }, { id: `B`, text: `phenomenon. In` }, { id: `C`, text: `phenomenon, in` }, { id: `D`, text: `phenomenon in` }],
